export function generateDetailEdges(grayObj,mask,cfg){if(!cfg.enabled)return null;const seg=[],w=grayObj.width,h=grayObj.height,g=grayObj.gray;for(let y=1;y<h-1;y+=2)for(let x=1;x<w-1;x+=2){const i=y*w+x;if(!mask[i])continue;const gx=-g[i-w-1]-2*g[i-1]-g[i+w-1]+g[i-w+1]+2*g[i+1]+g[i+w+1];const gy=-g[i-w-1]-2*g[i-w]-g[i-w+1]+g[i+w-1]+2*g[i+w]+g[i+w+1];const mag=Math.hypot(gx,gy);if(mag>cfg.detailThreshold*4)seg.push(Math.abs(gx)>Math.abs(gy)?{x1:x,y1:y,x2:x,y2:y+2}:{x1:x,y1:y,x2:x+2,y2:y})}const segments=seg.slice(0,cfg.maxNoise);return {id:'detail_edges',name:'Fine detail edges',type:'detail',color:cfg.color,strokeWidth:cfg.strokeWidth,visible:true,segments,stats:{segments:segments.length}}}
